                                                                                                                                                                                                                                                                        component
                                                                                                                                                                                                                                                                        from
                                                                                                                                                                                                                                                                        the
                                                                                                                                                                                                                                                                        dropdown
                                                                                                                                                                                                                                                                        to
                                                                                                                                                                                                                                                                        see
                                                                                                                                                                                                                                                                        its
                                                                                                                                                                                                                                                                        dependency
                                                                                                                                                                                                                                                                        expansion
                                                                                                                                                                                                                                                                        trends
